#!/usr/bin/env python3
# F8b-container-compose: audit a docker-compose file for trust-seam misconfig:
# privileged, docker.sock mount, host network/PID, dropped no-new-privileges,
# and host-bind of sensitive paths. READ-ONLY static audit; nothing is launched.
import os, sys
try:
    import yaml
except ImportError:
    print('install pyyaml: pip install pyyaml'); sys.exit(2)

SAMPLE = '''services:
  web:
    image: nginx:latest
    ports: ["127.0.0.1:8080:80"]
  worker:
    image: acme/worker:dev
    privileged: true
    network_mode: host
    pid: host
    volumes:
      - /var/run/docker.sock:/var/run/docker.sock
      - /:/host:ro
    cap_add: [SYS_ADMIN]
'''

def load():
    p = os.environ.get('COMPOSE')
    return yaml.safe_load(open(p).read()) if p else yaml.safe_load(SAMPLE)

doc = load()
findings=[]
for name, svc in (doc.get('services') or {}).items():
    if svc.get('privileged'): findings.append((name,'privileged: true -> near-root on host'))
    if str(svc.get('network_mode',''))=='host': findings.append((name,'network_mode: host -> bypasses network isolation'))
    if str(svc.get('pid',''))=='host': findings.append((name,'pid: host -> sees/affects host processes'))
    for c in (svc.get('cap_add') or []):
        if c in ('SYS_ADMIN','ALL','NET_ADMIN','SYS_PTRACE'): findings.append((name,f'cap_add: {c}'))
    for v in (svc.get('volumes') or []):
        vs = v if isinstance(v,str) else f"{v.get('source')}:{v.get('target')}"
        if 'docker.sock' in vs: findings.append((name,f'mounts docker.sock ({vs}) -> host takeover'))
        if vs.startswith('/:') or vs.startswith('/etc') or vs.startswith('/root'): findings.append((name,f'host-bind sensitive path ({vs})'))
    so = (svc.get('security_opt') or [])
    if not any('no-new-privileges' in str(x) for x in so):
        findings.append((name,'missing security_opt no-new-privileges:true'))

if findings:
    print('VULNERABLE: insecure compose defaults:')
    for n,f in findings: print(f'   - [{n}] {f}')
    print('Fix: drop privileged/host modes, remove docker.sock & host binds, add no-new-privileges, minimal caps.')
    sys.exit(0)
print('PASS: no insecure compose defaults detected.')
sys.exit(1)

XC-jwt-alg-confusion.script:
#!/usr/bin/env python3
# XC-jwt-alg-confusion: detect whether a JWT verifier accepts (a) alg=none and (b) an
# HS256 token signed with the RSA *public* key (RS256->HS256 confusion). READ-ONLY:
# all tokens are forged locally and checked against a LOCAL test verifier. No network.
import base64, hmac, hashlib, json, sys

def b64u(b): return base64.urlsafe_b64encode(b).rstrip(b'=')
def b64ud(s): return base64.urlsafe_b64decode(s + '='*(-len(s)%4))

# A stand-in RSA public key (PEM text). Public-by-definition; safe to embed (DEFANGED).
RSA_PUB = b'-----BEGIN PUBLIC KEY-----\nFAKE-EXAMPLE-PUBLIC-KEY\n-----END PUBLIC KEY-----\n'

def make(header, payload, key=b''):
    h=b64u(json.dumps(header).encode()); p=b64u(json.dumps(payload).encode())
    signing=h+b'.'+p
    if header['alg']=='none': sig=b''
    elif header['alg']=='HS256': sig=b64u(hmac.new(key, signing, hashlib.sha256).digest())
    else: sig=b'UNUSED'
    return (signing+b'.'+sig).decode()

def buggy_verify(token, rsa_pub):
    """Models a BUGGY verifier: trusts header alg; for HS256 uses the configured RSA
    public key bytes as the HMAC secret; accepts alg=none."""
    h_b64,p_b64,s_b64 = token.split('.')
    header=json.loads(b64ud(h_b64)); alg=header['alg']
    if alg=='none':
        return True, json.loads(b64ud(p_b64))
    if alg=='HS256':
        expect=b64u(hmac.new(rsa_pub, (h_b64+'.'+p_b64).encode(), hashlib.sha256).digest()).decode()
        if hmac.compare_digest(expect, s_b64):
            return True, json.loads(b64ud(p_b64))
    return False, None

admin={'sub':'attacker','role':'admin'}
t_none = make({'alg':'none','typ':'JWT'}, admin)
t_conf = make({'alg':'HS256','typ':'JWT'}, admin, key=RSA_PUB)

vuln=False
ok,claims=buggy_verify(t_none, RSA_PUB)
if ok: print('VULNERABLE: alg=none token accepted ->', claims); vuln=True
ok,claims=buggy_verify(t_conf, RSA_PUB)
if ok: print('VULNERABLE: RS256->HS256 confusion accepted (signed with RSA public key) ->', claims); vuln=True

if vuln:
    print('Fix: pin the expected alg server-side; never use the RSA public key as an HMAC secret; reject alg=none.')
    sys.exit(0)
print('PASS: verifier rejects alg=none and HS256-with-RSA-pubkey forgeries.')
sys.exit(1)

